import{_ as a,r as o,o as d,c as i,e as t,f as r,b as e,d as s}from"./app-212f8d91.js";const g={},h=s('<h1 id="传输层协议-tcp-与-udp" tabindex="-1"><a class="header-anchor" href="#传输层协议-tcp-与-udp" aria-hidden="true">#</a> 传输层协议 (TCP 与 UDP)</h1><blockquote><p><strong>引言</strong> 在前面的系列文章中，我们把 HTTP 协议扒了个底朝天。 但你有没有想过，HTTP 其实只是一个“发号施令”的老板（应用层），它只负责规定包裹里装什么（HTML/JSON），却从来不亲自送快递。</p><p>真正风里雨里穿梭在光缆和路由器之间，把数据从你的电脑搬运到服务器的，是底层两位性格迥异的快递员：<strong>TCP</strong> 和 <strong>UDP</strong>（传输层）。</p><p>很多前端觉得底层网络协议太抽象，跟自己没关系。但当你遇到 WebSocket 断线、视频直播卡顿、或者 HTTP/2 的性能瓶颈时，答案往往就藏在它们身上。 今天，我们就来详细扒一扒 TCP 与 UDP 的底层机制与核心差异。</p></blockquote><hr><h2 id="一、-一秒看懂核心差异-打电话-vs-寄明信片" tabindex="-1"><a class="header-anchor" href="#一、-一秒看懂核心差异-打电话-vs-寄明信片" aria-hidden="true">#</a> 一、 一秒看懂核心差异：打电话 vs 寄明信片</h2><p>在深入技术细节前，我们先用两个生活场景来定调：</p><ul><li><p><strong>TCP 就像“打电话”</strong>：</p><ul><li>拨号，对方接听，确认双方都能听见（<strong>建立连接</strong>）。</li><li>你一句我一句，如果对方没听清，你会重复一遍（<strong>可靠传输、丢包重传</strong>）。</li><li>说完后，双方礼貌互道再见，挂断电话（<strong>释放连接</strong>）。</li><li><strong>特点</strong>：极其靠谱，但建立连接很慢，沟通成本高。</li></ul></li><li><p><strong>UDP 就像“寄明信片”</strong>（或者村口的大喇叭广播）：</p><ul><li>你在明信片上写好地址，直接扔进邮筒（<strong>无连接</strong>）。</li><li>你根本不知道对方收没收到，哪怕明信片掉进下水道了，你也不管（<strong>不可靠</strong>）。</li><li><strong>特点</strong>：极其快速，不管死活，发了就完事。</li></ul></li></ul><hr><h2 id="二、-严谨的老实人-tcp-传输控制协议" tabindex="-1"><a class="header-anchor" href="#二、-严谨的老实人-tcp-传输控制协议" aria-hidden="true">#</a> 二、 严谨的老实人：TCP (传输控制协议)</h2><p><strong>TCP (Transmission Control Protocol)</strong> 是互联网上使用最广泛的协议。<strong>我们之前学过的 HTTP（1.1和2.0）、WebSocket，底层全都是 TCP。</strong></p><p>它的核心使命只有一个：<strong>宁可慢一点，也绝对不让数据丢失、错乱。</strong></p><h3 id="_1-核心机制-面试必考的三次握手与四次挥手" tabindex="-1"><a class="header-anchor" href="#_1-核心机制-面试必考的三次握手与四次挥手" aria-hidden="true">#</a> 1. 核心机制：面试必考的三次握手与四次挥手</h3><p>TCP 想要保证可靠，就必须在发数据之前，先确认网络通道是通畅的。</p><p><strong>🤝 建立连接：三次握手 (Three-way Handshake)</strong> 为了防止旧的无效连接请求突然传到服务器产生误会，TCP 必须进行三次通信来确认身份：</p><ol><li><strong>客户端</strong>：“喂，能听到我说话吗？”（发送 <code>SYN</code> 报文，请求建立连接）</li><li><strong>服务端</strong>：“我能听到！那你能听到我说话吗？”（发送 <code>SYN + ACK</code> 报文，同意连接并反问）</li><li><strong>客户端</strong>：“我也能听到！那我们开始发数据吧。”（发送 <code>ACK</code> 报文，确认收到） <em>(完成这三步，TCP 连接才算真正建立，之后 HTTP 才能开始发请求)</em>。</li></ol><p><strong>👋 断开连接：四次挥手 (Four-way Teardown)</strong> 因为 TCP 是全双工的（双方可以同时发数据），所以断开时必须两边都明确表示“我发完了”。</p><ol><li><strong>客户端</strong>：“我要说的话全都说完了，我想挂了。”（发 <code>FIN</code>）</li><li><strong>服务端</strong>：“好的，我知道了，但我还有点数据没传完，你再等一下。”（发 <code>ACK</code>）</li><li><strong>服务端</strong>（过了一会儿）：“我的数据也传完了，可以挂电话了。”（发 <code>FIN</code>）</li><li><strong>客户端</strong>：“好的，再见！”（发 <code>ACK</code>。客户端等一会儿没回复，彻底关闭连接）。</li></ol><h3 id="_2-tcp-的看家本领-可靠性保证" tabindex="-1"><a class="header-anchor" href="#_2-tcp-的看家本领-可靠性保证" aria-hidden="true">#</a> 2. TCP 的看家本领：可靠性保证</h3><p>除了握手，TCP 在传输过程中还做了极其繁重的工作：</p><ul><li><strong>按序到达</strong>：把大文件切成小块（报文段），编上序号。即使网络导致乱序，接收端也能按序号拼好。</li><li><strong>超时重传</strong>：发一个包，启动一个定时器。如果规定时间内没收到对方的 <code>ACK</code> 确认，TCP 就认为包丢了，<strong>强制重新发一次</strong>。</li><li><strong>拥塞控制 (Congestion Control)</strong>：如果网络很卡，TCP 会主动把发送速度降下来，防止网络彻底瘫痪。</li></ul><h3 id="_3-致命痛点-tcp-队头阻塞" tabindex="-1"><a class="header-anchor" href="#_3-致命痛点-tcp-队头阻塞" aria-hidden="true">#</a> 3. 致命痛点：TCP 队头阻塞</h3><p>还记得我们在 HTTP/2 那篇文章里提到的痛点吗？ 因为 TCP 太老实了，它规定<strong>数据必须按顺序交给应用层</strong>。如果第 2 个包在路上丢了，哪怕第 3、4、5 个包早就到了，TCP 也会把它们死死扣留在操作系统的缓冲区里，直到第 2 个包重传成功。这就是万恶的 <strong>TCP 层队头阻塞</strong>，也是 HTTP/2 性能受限的元凶。</p><hr><h2 id="三、-莽撞的飙车党-udp-用户数据报协议" tabindex="-1"><a class="header-anchor" href="#三、-莽撞的飙车党-udp-用户数据报协议" aria-hidden="true">#</a> 三、 莽撞的飙车党：UDP (用户数据报协议)</h2><p><strong>UDP (User Datagram Protocol)</strong> 的设计哲学与 TCP 完全相反：<strong>天下武功，唯快不破。</strong></p><h3 id="_1-核心特征-无连接、不可靠" tabindex="-1"><a class="header-anchor" href="#_1-核心特征-无连接、不可靠" aria-hidden="true">#</a> 1. 核心特征：无连接、不可靠</h3><ul><li><strong>没有握手</strong>：UDP 不管三七二十一，拿到数据，套上目的 IP 和端口，直接往网络里塞。毫无建连延迟。</li><li><strong>不保证交付</strong>：UDP 发出去的包，就像泼出去的水。丢包了？不管。顺序乱了？不管。</li><li><strong>没有拥塞控制</strong>：哪怕网络已经挤成一锅粥了，UDP 依然会按照你设定的速度疯狂发包。</li></ul><h3 id="_2-为什么我们需要这么-烂-的协议" tabindex="-1"><a class="header-anchor" href="#_2-为什么我们需要这么-烂-的协议" aria-hidden="true">#</a> 2. 为什么我们需要这么“烂”的协议？</h3><p>看到这里你可能会问，这么不可靠的协议，留着过年吗？ 恰恰相反，在某些对<strong>实时性要求极高</strong>的场景，TCP 的“可靠”反而成了致命伤。</p>',28),c=t("li",null,[t("strong",null,"场景一：视频直播 / 微信视频通话 (实时音视频 WebRTC)"),r(" 如果用 TCP，一旦网络卡顿丢了一个视频帧，TCP 就会死等重传，导致你的视频画面卡死 3 秒。 如果用 UDP，丢了一帧就丢了，大不了屏幕上出现一点马赛克，但视频绝对是"),t("strong",null,"流畅且实时"),r("的。对于直播来说，0.1秒的马赛克绝对比卡顿 3 秒要好得多。")],-1),P=t("li",null,[t("strong",null,"场景二：多人在线竞技游戏 (FPS/MOBA)"),r(" 你玩《王者荣耀》按了一个闪现。如果包丢了，TCP 重传这个操作，等 1 秒后服务器收到，你早就被击杀了。游戏通常底层使用 UDP，结合自己的应用层算法来保证极致的低延迟。")],-1),T=t("strong",null,"场景三：DNS 域名解析",-1),p={href:"http://baidu.com",target:"_blank",rel:"noopener noreferrer"},u=s('<hr><h2 id="四、-巅峰对决-tcp-vs-udp-核心对比" tabindex="-1"><a class="header-anchor" href="#四、-巅峰对决-tcp-vs-udp-核心对比" aria-hidden="true">#</a> 四、 巅峰对决：TCP vs UDP 核心对比</h2><p>这张表格是面试中最常被问到的，请务必刻在脑子里：</p><table><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">TCP</th><th style="text-align:left;">UDP</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>连接状态</strong></td><td style="text-align:left;"><strong>面向连接</strong> (必须先三次握手)</td><td style="text-align:left;"><strong>无连接</strong> (直接发)</td></tr><tr><td style="text-align:left;"><strong>可靠性</strong></td><td style="text-align:left;"><strong>绝对可靠</strong> (不丢包、不乱序)</td><td style="text-align:left;"><strong>不可靠</strong> (尽最大努力交付)</td></tr><tr><td style="text-align:left;"><strong>传输效率</strong></td><td style="text-align:left;"><strong>慢</strong> (有握手和重传等沉重开销)</td><td style="text-align:left;"><strong>极快</strong> (头部只有 8 个字节，0开销)</td></tr><tr><td style="text-align:left;"><strong>数据传输形式</strong></td><td style="text-align:left;">面向<strong>字节流</strong> (粘包问题)</td><td style="text-align:left;">面向<strong>报文</strong> (保留消息边界)</td></tr><tr><td style="text-align:left;"><strong>前端相关应用</strong></td><td style="text-align:left;"><strong>HTTP/1.1, HTTP/2, WebSocket</strong><br>下载文件、发邮件、常规网页接口</td><td style="text-align:left;"><strong>WebRTC</strong> (音视频通话)<br>DNS 解析、HTTP/3</td></tr></tbody></table><hr><h2 id="五、-历史的轮回-http-3-与-udp-的联姻" tabindex="-1"><a class="header-anchor" href="#五、-历史的轮回-http-3-与-udp-的联姻" aria-hidden="true">#</a> 五、 历史的轮回：HTTP/3 与 UDP 的联姻</h2><p>文章的最后，我们让知识产生闭环，回到我们的 HTTP 系列。</p><p>既然 TCP 如此可靠，UDP 如此快速，那能不能把两者的优点结合起来呢？ <strong>能！这就是 Google 推出的 QUIC 协议，也就是 HTTP/3 的底层基石。</strong></p><p>既然 TCP 的底层代码写死在操作系统的内核里，改不动了。谷歌的工程师干脆<strong>抛弃了 TCP，底层直接使用 UDP</strong>。 然后，他们在 UDP 之上（应用层内部）用代码自己实现了一套类似 TCP 的丢包重传机制。</p><p><strong>HTTP/3 (QUIC) 的神仙操作：</strong></p><ol><li><strong>0-RTT 建连</strong>：利用 UDP 的无连接特性，首次握手极快，再次连接甚至不需要握手时间。</li><li><strong>彻底消灭队头阻塞</strong>：因为底层是 UDP，没有 TCP 那套“按序交付”的死板规定。如果发了 10 张图片，第 2 张丢了，只有第 2 张的流会等待重传，其他 9 张图片直接交给前端渲染！</li></ol><p>兜兜转转三十年，原本被嫌弃“不可靠”的 UDP，最终成了拯救 HTTP 性能瓶颈的超级英雄。</p><h2 id="五、tcp连接示意图" tabindex="-1"><a class="header-anchor" href="#五、tcp连接示意图" aria-hidden="true">#</a> 五、TCP连接示意图</h2><h3 id="_1-三次握手建立连接" tabindex="-1"><a class="header-anchor" href="#_1-三次握手建立连接" aria-hidden="true">#</a> 1. 三次握手建立连接</h3>',14),C=t("h3",{id:"_2-四次挥手断开连接",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#_2-四次挥手断开连接","aria-hidden":"true"},"#"),r(" 2. 四次挥手断开连接")],-1),f=t("blockquote",null,[t("p",null,[t("strong",null,"结语"),r(" TCP 就像一位严谨的老管家，确保我们发出的每一个 JSON、每一张图片都完好无损地抵达； UDP 就像一位狂野的赛车手，在视频直播和游戏的赛道上追求着极致的低延迟。")]),t("p",null,"了解传输层，不仅是为了应付面试中的“三次握手”，更是为了让我们在面对业务架构选型时，能够根据“要可靠还是要速度”，做出最正确的判断。"),t("p",null,[r("在 Node.js 中，如果你想直接玩 TCP，用的是 "),t("code",null,"net"),r(" 模块；如果你想玩 UDP，用的是 "),t("code",null,"dgram"),r(" 模块。")])],-1),x=t("hr",null,null,-1);function U(D,y){const l=o("ExternalLinkIcon"),n=o("Mermaid");return d(),i("div",null,[h,t("ul",null,[c,P,t("li",null,[T,r(" DNS 只是发一个极小的包去问“"),t("a",p,[r("baidu.com"),e(l)]),r(" 的 IP 是多少”。为了这么点数据去搞复杂的三次握手太浪费了，UDP 一去一回瞬间搞定。")])]),u,e(n,{id:"mermaid-328",code:""}),C,e(n,{id:"mermaid-332",code:""}),f,x])}const m=a(g,[["render",U],["__file","07.html.vue"]]);export{m as default};
